// Detect search type (UMKM or Jasa)
const message = $input.first().json.body?.body || $input.first().json.body?.message || '';
const from = $input.first().json.body?.from || $input.first().json.body?.sender || '';

const isJasa = message.toLowerCase().includes('jasa') || 
               message.toLowerCase().includes('tukang');

const endpoint = isJasa ? '/jasa/search' : '/umkm/search';

// Extract search keyword
let keyword = message;
const prefixes = ['umkm', 'jasa', 'produk', 'tukang', 'usaha'];
for (const prefix of prefixes) {
  if (keyword.toLowerCase().startsWith(prefix)) {
    keyword = keyword.substring(prefix.length).trim();
    break;
  }
}

return {
  from: from,
  message: message,
  searchType: isJasa ? 'JASA' : 'UMKM',
  endpoint: endpoint,
  keyword: keyword || 'semua'
};

// Format search results
const data = $input.first().json.data || [];
const count = $input.first().json.count || 0;
const prevNode = $input.first().json;
const searchType = prevNode.searchType || 'UMKM';
const websiteLink = $input.first().json.website_link || '';

if (count === 0) {
  return {
    to: prevNode.from,
    message: '🙏 Maaf, data belum ditemukan.\n\nSilakan coba kata kunci lain.\nContoh: Bakso, Madu, Tukang Piket\n\nKetik MENU untuk kembali.'
  };
}

let message = searchType === 'JASA' 
  ? '🛠️ Hasil Pencarian Jasa:\n\n'
  : '🛍️ Hasil Pencarian UMKM:\n\n';

data.forEach((item, index) => {
  message += `${index + 1}️⃣ ${item.name}\n`;
  message += `📦 Produk: ${item.product}\n`;
  message += `📍 ${item.address}\n`;
  message += `📱 WA: ${item.contact_link}\n\n`;
});

if (websiteLink) {
  message += `🔎 Lihat lebih banyak di:\n${websiteLink}\n\n`;
}

message += 'Ketik MENU untuk kembali.';

return {
  to: prevNode.from,
  message: message
};
